export const getBlogPost = (slug?: string): BlogEntry | undefined =>
  blogPosts.find((p) => p.slug === slug);

export const pickLocale = (lang: string): BlogLocale =>
  lang === 'sv' ? 'sv' : lang === 'no' ? 'no' : 'en';
